import 'package:btech_tokens/btech_tokens.dart';
import 'package:flutter/material.dart';

/// Dark rounded balloon body — JUST the container. The arrow is rendered
/// as a separate `Positioned` widget alongside this one (el_tooltip pattern).
///
/// Width wraps content up to [maxWidth] px. Height is determined by the
/// text/content and measured at runtime via a hidden first-pass overlay
/// (see `_BTTooltipState._measureBalloon`).
class BTTooltipBalloonBody extends StatelessWidget {
  const BTTooltipBalloonBody({
    this.text,
    this.content,
    super.key,
  });

  final String? text;
  final Widget? content;

  /// Maximum balloon width. Used as the initial size estimate before
  /// the two-pass measurement resolves the actual rendered size.
  static double get maxWidth => 280.0;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;
    final bg = c.bg.inverse;

    // IntrinsicWidth makes the balloon shrink-wrap its content width while
    // ConstrainedBox caps it at maxWidth — short labels get a narrow pill,
    // long text wraps inside the 280 px boundary.
    return Material(
      type: MaterialType.transparency,
      child: IntrinsicWidth(
        child: ConstrainedBox(
          constraints: BoxConstraints(maxWidth: maxWidth),
          child: Container(
            decoration: BoxDecoration(
              color: bg,
              borderRadius: BorderRadius.circular(r.sm),
              boxShadow: BTShadow.elevation.xl,
            ),
            padding: EdgeInsets.all(16.0),
            child: content ??
                Text(
                  text ?? '',
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 14.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 14,
                    color: c.text.inverse,
                  ),
                ),
          ),
        ),
      ),
    );
  }
}

